import React from 'react';
import styled from '@emotion/styled';
import Layout from '../components/GlobalLayout';
import GlobalStyles from '../components/GlobalStyles';
import PostCard from '../components/PostCard';
import { graphql, useStaticQuery, Link } from 'gatsby';
import { GatsbyImage, getImage } from 'gatsby-plugin-image';
import {
  FeaturedCard,
  FeaturedImageWrapper,
  FeaturedNoThumbnail,
  FeaturedContent,
  FeaturedBadge,
  FeaturedLabel,
  FeaturedCategoryTag,
  FeaturedTitle,
  FeaturedExcerpt,
  FeaturedMeta,
  FeaturedMetaDot,
  FeaturedReadMore,
  FeaturedLink,
  SectionHeader,
  SectionTitle,
  SectionMore,
  PostGrid,
  Section,
  EmptyState,
  HeroSection,
  HeroInner,
  HeroEyebrow,
  HeroBadge,
  HeroTitle,
  HeroSubtitle,
  HeroCTA,
  CTAButton,
  CTASecondary,
} from 'src/styles/PageStyles';

// ============================================================
// index.tsx — 당근(Daangn) 블로그 스타일 메인 페이지 재설계
// Stitch MCP 디자인 반영
// ============================================================

const PageInner = styled.div`
  max-width: 1180px;
  margin: 0 auto;
  padding: 0 var(--space-5) var(--space-24);

  @media (min-width: 640px) {
    padding: 0 var(--space-6) var(--space-24);
  }

  @media (min-width: 1024px) {
    padding: 0 var(--space-8) var(--space-32);
  }
`;

const MetaDot = styled.span`
  width: 3px;
  height: 3px;
  background: var(--color-border-strong);
  border-radius: 50%;
  flex-shrink: 0;
  display: inline-block;
`;

const StatsBar = styled.div`
  display: flex;
  align-items: center;
  gap: var(--space-4);
  flex-wrap: wrap;
`;

const Stat = styled.div`
  display: flex;
  flex-direction: column;

  .value {
    font-size: var(--fs-title-xl);
    font-weight: var(--fw-black);
    color: var(--color-text-primary);
    letter-spacing: -0.04em;
    line-height: 1;
  }

  .label {
    font-size: var(--fs-xs);
    color: var(--color-text-tertiary);
    font-weight: var(--fw-medium);
    margin-top: 2px;
  }
`;

const StatDivider = styled.div`
  width: 1px;
  height: 32px;
  background: var(--color-border-subtle);
`;

const FeaturedSection = styled.div`
  margin-bottom: var(--space-16);

  @media (min-width: 768px) {
    margin-bottom: var(--space-20);
  }
`;

const FeaturedSectionHeader = styled.div`
  display: flex;
  align-items: center;
  gap: var(--space-3);
  margin-bottom: var(--space-6);
`;

const FeaturedSectionTitle = styled.h2`
  font-size: var(--fs-title-md);
  font-weight: var(--fw-bold);
  color: var(--color-text-primary);
  margin: 0;
  letter-spacing: -0.025em;
`;

const FeaturedBadgeInline = styled.span`
  display: inline-flex;
  align-items: center;
  padding: 2px var(--space-2);
  background: var(--color-brand-primary);
  color: var(--color-brand-on);
  border-radius: var(--radius-xs);
  font-size: var(--fs-xs);
  font-weight: var(--fw-bold);
  letter-spacing: var(--ls-wider);
  text-transform: uppercase;
`;

const IndexPage = () => {
  const data = useStaticQuery(graphql`
    query {
      allMarkdownRemark(sort: { frontmatter: { date: DESC } }, limit: 10) {
        nodes {
          id
          frontmatter {
            title
            date(formatString: "YYYY년 MM월 DD일")
            category
            thumbnail {
              childImageSharp {
                gatsbyImageData(width: 900, height: 560, placeholder: BLURRED)
              }
            }
          }
          excerpt(pruneLength: 200)
          fields {
            slug
          }
          timeToRead
        }
        totalCount
      }
    }
  `);

  const posts = data.allMarkdownRemark.nodes;
  const totalCount = data.allMarkdownRemark.totalCount;
  const featuredPost = posts[0];
  const restPosts = posts.slice(1);

  const studyCount = posts.filter((p: any) => p.frontmatter.category === 'study').length;
  const projectCount = posts.filter((p: any) => p.frontmatter.category === 'project').length;

  const getFeaturedImage = (post: any) => {
    const img = post?.frontmatter?.thumbnail?.childImageSharp?.gatsbyImageData;
    return img ? getImage(img) : null;
  };

  return (
    <>
      <GlobalStyles />
      <Layout>
        <PageInner>
          {/* ── Hero Section ── */}
          <HeroSection>
            <HeroInner>
              <HeroEyebrow>
                <HeroBadge>Dev Blog</HeroBadge>
              </HeroEyebrow>

              <HeroTitle>
                개발을 기록하고<br />
                성장을 나누는 공간
              </HeroTitle>

              <HeroSubtitle>
                공부하고 경험한 것들을 정리합니다.
                함께 읽고 함께 성장해요.
              </HeroSubtitle>

              <HeroCTA>
                <CTAButton to="/study/">
                  스터디 보기
                </CTAButton>
                <CTASecondary to="/project/">
                  프로젝트 보기
                </CTASecondary>
              </HeroCTA>

              {totalCount > 0 && (
                <StatsBar>
                  <Stat>
                    <span className="value">{totalCount}</span>
                    <span className="label">전체 글</span>
                  </Stat>
                  {studyCount > 0 && (
                    <>
                      <StatDivider />
                      <Stat>
                        <span className="value">{studyCount}</span>
                        <span className="label">스터디</span>
                      </Stat>
                    </>
                  )}
                  {projectCount > 0 && (
                    <>
                      <StatDivider />
                      <Stat>
                        <span className="value">{projectCount}</span>
                        <span className="label">프로젝트</span>
                      </Stat>
                    </>
                  )}
                </StatsBar>
              )}
            </HeroInner>
          </HeroSection>

          {/* ── Featured Post ── */}
          {featuredPost && (
            <FeaturedSection>
              <FeaturedSectionHeader>
                <FeaturedSectionTitle>최신 글</FeaturedSectionTitle>
                <FeaturedBadgeInline>NEW</FeaturedBadgeInline>
              </FeaturedSectionHeader>

              <FeaturedLink
                to={`/${featuredPost.frontmatter.category}${featuredPost.fields.slug}`}
              >
                <FeaturedCard>
                  <FeaturedImageWrapper>
                    {getFeaturedImage(featuredPost) ? (
                      <GatsbyImage
                        image={getFeaturedImage(featuredPost)!}
                        alt={featuredPost.frontmatter.title}
                      />
                    ) : (
                      <FeaturedNoThumbnail>✍️</FeaturedNoThumbnail>
                    )}
                  </FeaturedImageWrapper>

                  <FeaturedContent>
                    <FeaturedBadge>
                      <FeaturedLabel>최신 글</FeaturedLabel>
                      <FeaturedCategoryTag>
                        {featuredPost.frontmatter.category}
                      </FeaturedCategoryTag>
                    </FeaturedBadge>

                    <FeaturedTitle>{featuredPost.frontmatter.title}</FeaturedTitle>
                    <FeaturedExcerpt>{featuredPost.excerpt}</FeaturedExcerpt>

                    <FeaturedMeta>
                      <time>{featuredPost.frontmatter.date}</time>
                      <FeaturedMetaDot />
                      <span>
                        {featuredPost.timeToRead
                          ? `${featuredPost.timeToRead}분 읽기`
                          : '5분 읽기'}
                      </span>
                    </FeaturedMeta>

                    <FeaturedReadMore>
                      읽어보기
                      <svg className="arrow" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                        <line x1="5" y1="12" x2="19" y2="12" />
                        <polyline points="12 5 19 12 12 19" />
                      </svg>
                    </FeaturedReadMore>
                  </FeaturedContent>
                </FeaturedCard>
              </FeaturedLink>
            </FeaturedSection>
          )}

          {/* ── 포스트 그리드 ── */}
          <Section>
            <SectionHeader>
              <SectionTitle>모든 글</SectionTitle>
              <SectionMore to="/study/">
                더 보기
                <svg className="icon" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                  <line x1="5" y1="12" x2="19" y2="12" />
                  <polyline points="12 5 19 12 12 19" />
                </svg>
              </SectionMore>
            </SectionHeader>

            {restPosts.length > 0 ? (
              <PostGrid>
                {restPosts.map((post: any) => (
                  <PostCard
                    key={post.id}
                    title={post.frontmatter.title}
                    excerpt={post.excerpt}
                    date={post.frontmatter.date}
                    category={post.frontmatter.category}
                    slug={post.fields.slug}
                    readTime={
                      post.timeToRead ? `${post.timeToRead}분` : undefined
                    }
                    thumbnail={
                      post.frontmatter.thumbnail?.childImageSharp
                        ?.gatsbyImageData
                    }
                  />
                ))}
              </PostGrid>
            ) : posts.length === 0 ? (
              <EmptyState>
                <span className="emoji">✍️</span>
                <h3>아직 글이 없어요</h3>
                <p>첫 번째 포스트를 작성해보세요!</p>
              </EmptyState>
            ) : null}
          </Section>
        </PageInner>
      </Layout>
    </>
  );
};

export const Head = () => (
  <>
    <title>Dev.log — 개발 기록 블로그</title>
    <meta name="description" content="개발 공부와 프로젝트를 기록하는 블로그" />
    <meta property="og:title" content="Dev.log" />
    <meta property="og:description" content="개발 공부와 프로젝트를 기록하는 블로그" />
    <meta property="og:type" content="website" />
  </>
);

export default IndexPage;
